local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxRankCtrl:LxBaseCtrl
local LxRankCtrl = classX("LxRankCtrl", LxBaseCtrl)

function LxRankCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxRankCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

-- 获取排行榜红点总数
function LxRankCtrl:GetRedNum()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncOpnIdConst.Rank, FuncOpenTipsEnum.None) then
        return 0
    end

    local num = ModuleCenter.Rank:GetRankLikeRedNum()
    num = num + ModuleCenter.Rank:GetMilestoneRedNum()
    return num
end


function LxRankCtrl:GetRankingListByType(rankType)
    if not self._rankingTypeList then
        self._rankingTypeList = {}
    end
    local rankingTypes = self._rankingTypeList[rankType]
    if ModuleCenter.Debug.isTest then
        rankingTypes = nil
    end
    if not rankingTypes then
        rankingTypes = {}
        for k,v in pairs(GameTable.LeaderboardingRef) do
            if v.type == rankType then
                table.insert(rankingTypes,{
                    btnName = I18nText(v.name),
                    btnName1 = I18nText(v.name1),
                    type = rankType,
                    btnType = rankType,
                    refId = k,
                    sort = v.sort,
                })
            end
        end
        table.sort(rankingTypes,function(a,b) return a.sort < b.sort end)
        self._rankingTypeList[rankType] = rankingTypes
    end
    return rankingTypes
end

