function LxRankCtrl:GetTotalRankList(rankType)
    if not self._totalRankList then
        self._totalRankList = {}
        for k,v in pairs(GameTable.LeaderboardingRef) do
            if v.showRank == 1 then
                local rankType = v.type
                if not self._totalRankList[rankType] then
                    self._totalRankList[rankType] = {}
                end
                table.insert(self._totalRankList[rankType],v)
            end
        end
    end
    if not rankType then
        return self._totalRankList
    end
    return self._totalRankList[rankType] or {}
end

function LxRankCtrl:GetRankListByType(rankType, page)
    local rankList = {}
    for k,v in pairs(GameTable.LeaderboardingRef) do
        if v.type == rankType and (not page or v.page == page) then
            table.insert(rankList,v)
        end
    end
    return rankList
end
return LxRankCtrl
